function createSectionHeader(text) {
    return new Paragraph({
        spacing: { before: 400, after: 200 },
        border: { bottom: { style: BorderStyle.SINGLE, size: 6, color: COLORS.navyBlue } },
        children: [
            new TextRun({ text: text.toUpperCase(), bold: true, color: COLORS.navyBlue, font: "Arial", size: 32 })
        ]
    });
}

function createSubHeader(text) {
    return new Paragraph({
        spacing: { before: 300, after: 150 },
        children: [
            new TextRun({ text: text, bold: true, color: COLORS.teal, font: "Arial", size: 26 })
        ]
    });
}

function createPara(text, opts = {}) {
    return new Paragraph({
        spacing: { after: 120 },
        children: [new TextRun({ text, font: "Arial", size: 22, ...opts })]
    });
}

function createBullet(text, opts = {}) {
    return new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        spacing: { after: 80 },
        children: [new TextRun({ text, font: "Arial", size: 22, ...opts })]
    });
}

function createKeyValue(key, value, valueOpts = {}) {
    return new Paragraph({
        spacing: { after: 80 },
        children: [
            new TextRun({ text: `${key}: `, bold: true, font: "Arial", size: 22 }),
            new TextRun({ text: value, font: "Arial", size: 22, ...valueOpts })
        ]
    });
}

function getTierColor(tier) {
    const colors = { 0: COLORS.elite, 1: COLORS.strongD1, 2: COLORS.midD1, 3: COLORS.safety };
    return colors[tier] || COLORS.lightGray;
}

function createHeaderCell(text, width = 2000) {
    return new TableCell({
        borders,
        shading: { fill: COLORS.navyBlue, type: ShadingType.CLEAR },
        width: { size: width, type: WidthType.DXA },
        margins: { top: 80, bottom: 80, left: 100, right: 100 },
        children: [new Paragraph({ children: [new TextRun({ text, bold: true, color: COLORS.white, font: "Arial", size: 20 })] })]
    });
}

function createDataCell(text, opts = {}) {
    const { fill, bold, color, width } = opts;
    return new TableCell({
        borders,
        shading: fill ? { fill, type: ShadingType.CLEAR } : undefined,
        width: width ? { size: width, type: WidthType.DXA } : undefined,
        margins: { top: 60, bottom: 60, left: 100, right: 100 },
        children: [new Paragraph({ children: [new TextRun({ text: String(text), font: "Arial", size: 20, bold, color })] })]
    });
}

